// Extract all useful properties from the Notion page into a flat object
const props = $json.properties;

const getValue = (prop) => {
  if (!prop) return '';
  if (prop.title) return prop.title.map(t => t.plain_text).join('');
  if (prop.rich_text) return prop.rich_text.map(t => t.plain_text).join('');
  if (prop.select) return prop.select?.name || '';
  if (prop.url) return prop.url || '';
  if (prop.date) return prop.date?.start || '';
  return '';
};

return [{
  json: {
    notionPageId: $json.id,
    signal: getValue(props['Signal']),
    dateCaptured: getValue(props['Date Captured']),
    sourceChannel: getValue(props['Source Channel']),
    originalMessage: getValue(props['Original Message']),
    author: getValue(props['Author']),
    signalType: getValue(props['Signal Type']),
    sentiment: getValue(props['Sentiment']),
    urgency: getValue(props['Urgency']),
    aiAnalysis: getValue(props['AI Analysis']),
    customerMentioned: getValue(props['Customer Mentioned']),
    routeDestination: getValue(props['Route Destination']),
    routeStatus: getValue(props['Route Status']),
    threadUrl: getValue(props['Thread URL']),
    slackMessageId: getValue(props['Slack Message ID'])
  }
}];

// Extract Jira bug ticket reference
const jiraKey = $json.key || 'PROJ-???';
const signalData = $('Read Signal Details').first().json;

return [{
  json: {
    ...signalData,
    routedReference: jiraKey,
    routedUrl: `https://company.atlassian.net/browse/${jiraKey}`
  }
}];

// Extract Jira feature ticket reference
const jiraKey = $json.key || 'PROJ-???';
const signalData = $('Read Signal Details').first().json;

return [{
  json: {
    ...signalData,
    routedReference: jiraKey,
    routedUrl: `https://company.atlassian.net/browse/${jiraKey}`
  }
}];

// Generate a readable reference for the RICE+ entry
const riceRef = 'RICE-' + String(Math.floor(Math.random() * 900) + 100).padStart(3, '0');
const signalData = $('Read Signal Details').first().json;

return [{
  json: {
    ...signalData,
    routedReference: riceRef,
    routedUrl: $json.url || '#',
    notionRicePageId: $json.id || ''
  }
}];

// Generate a health reference
const signalData = $('Read Signal Details').first().json;
const healthRef = signalData.customerMentioned
  ? signalData.customerMentioned.replace(/\s+/g, '').substring(0, 3).toUpperCase() + '-HEALTH-' + String(Math.floor(Math.random() * 900) + 100).padStart(3, '0')
  : 'UNK-HEALTH-' + String(Math.floor(Math.random() * 900) + 100).padStart(3, '0');

return [{
  json: {
    ...signalData,
    routedReference: healthRef,
    routedUrl: $json.url || '#',
    notionHealthPageId: $json.id || ''
  }
}];

// Generate a sprint reference
const signalData = $('Read Signal Details').first().json;
const sprintRef = 'SPRINT-' + String(Math.floor(Math.random() * 900) + 100).padStart(3, '0');

return [{
  json: {
    ...signalData,
    routedReference: sprintRef,
    routedUrl: $json.url || '#',
    notionSprintPageId: $json.id || ''
  }
}];

// Build Slack Thread Reply
const signal = $json;

// Determine the channel ID from the name
const channelMap = {
  '#product': 'C01PRODUCT',
  '#support': 'C02SUPPORT',
  '#sales': 'C03SALES',
  '#engineering': 'C04ENGINEERING',
  '#general': 'C05GENERAL'
};

const channelId = channelMap[signal.sourceChannel] || signal.sourceChannel;

// Build confirmation message
const destinationLabel = {
  'Jira Bug': 'Jira Bug Ticket',
  'Jira Feature': 'Jira Feature Story',
  'RICE+ Backlog': 'RICE+ Feature Backlog',
  'Customer Health': 'Customer Health Tracker',
  'Sprint Backlog': 'Sprint 24 Backlog'
}[signal.routeDestination] || signal.routeDestination;

const replyMessage = `Captured and routed to *${signal.routedReference}* (${destinationLabel})`;

return [{
  json: {
    ...signal,
    slackChannelId: channelId,
    replyMessage: replyMessage
  }
}];
